return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'de_CH','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Bitte aktualisiere das TranslatePress - Multilingual Plugin auf Version %1$s oder höher, damit %2$s korrekt funktioniert.','Please install and activate the TranslatePress - Multilingual plugin'=>'Bitte installiere und aktiviere das TranslatePress - Multilingual Plugin','Install & Activate'=>'Installieren & Aktivieren','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Bitte aktualisiere TranslatePress - Multilingual auf Version %2$s oder neuer. Die aktuell installierte Version von TranslatePress - Multilingual ist nicht mehr kompatibel mit der aktuellen Version von %1$s.','All TranslatePress functionalities are disabled until then.'=>'Alle TranslatePress-Funktionen sind bis dahin deaktiviert.','Update Now'=>'Jetzt aktualisieren','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Dieses TranslatePress-Add-on wurde ins Haupt-Plugin migriert und wird nicht mehr verwendet. Du kannst es löschen.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> benötigt mindestens PHP-Version 5.6.20+ zum Ausführen. Das ist die <a href="%s">Mindestanforderung der neuesten WordPress-Version</a>. Bitte wende dich an deinen Server-Administrator, um deine PHP-Version zu aktualisieren.','Advanced'=>'Erweitert','Settings saved.'=>'Einstellungen gespeichert.','Are you sure you want to remove this item?'=>'Bist du sicher, dass du dieses Element entfernen möchtest?','Remove'=>'Entfernen','Add'=>'Hinzufügen','Select...'=>'Auswählen...','[%s] Low TranslatePress AI Words'=>'[%s] TranslatePress AI-Wörter werden knapp','upgrade your plan or get extra AI Words'=>'Plan upgraden oder zusätzliche AI-Wörter erhalten','upgrade your plan'=>'Plan upgraden','TranslatePress AI words are running low on your site.'=>'Die TranslatePress AI-Wörter auf deiner Website werden knapp.','Current status: %s words remaining'=>'Aktueller Status: Noch %s Wörter übrig','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Sobald die verbleibenden AI-Wörter aufgebraucht sind, wird die automatische Übersetzung über TranslatePress AI pausiert.','To continue translating your content, please %1$s over at %2$s'=>'Um deine Inhalte weiter zu übersetzen, bitte %1$s auf %2$s','Manage Notification: %s'=>'Benachrichtigung verwalten: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Es ist eine neue Version von %1$s verfügbar. %2$sDetails zu Version %3$s anzeigen%4$s oder %5$sjetzt aktualisieren%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Es ist eine neue Version von %1$s verfügbar. %2$sDetails zu Version %3$s anzeigen%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Um Aktualisierungen zu aktivieren, bitte %1$sgib deinen Lizenzschlüssel ein%2$s. Brauchst du einen Lizenzschlüssel? %3$sJetzt kaufen%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Um Aktualisierungen zu aktivieren, gehe bitte zur %1$sLizenzseite%2$s und überprüfe, ob du eine gültige Lizenz hast.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Um Aktualisierungen zu aktivieren, muss deine Lizenz erneuert werden. Bitte gehe zur %1$sTranslatePress Account%2$s-Seite und melde dich an, um sie zu erneuern.','You do not have permission to install plugin updates'=>'Du hast keine Berechtigung, Plugin-Aktualisierungen zu installieren','Error'=>'Fehler','Your TranslatePress license key is invalid or missing.'=>'Dein TranslatePress-Lizenzschlüssel ist ungültig oder fehlt.','Your license key expired on %s.'=>'Dein Lizenzschlüssel ist am %s abgelaufen.','Your license key has been disabled.'=>'Dein Lizenzschlüssel wurde deaktiviert.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Dein Lizenzschlüssel ist für diese URL deaktiviert. Aktiviere ihn erneut unter <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Websites verwalten.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Lizenzschlüssel stimmt nicht überein.</strong> Die eingegebene Lizenz entspricht nicht der installierten TranslatePress-Version.</p><p>Bitte überprüfe, ob du die korrekte Version für deine Lizenz aus deinem TranslatePress Account installiert hast.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Wenn du nur das kostenlose Plugin installiert hast, aber eine kostenpflichtige Lizenz hinzugefügt hast, installiere bitte das kostenpflichtige Plugin aus deinem TranslatePress Account.','Your license key has reached its activation limit.'=>'Dein Lizenzschlüssel hat das Aktivierungslimit erreicht.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Erweitere deinen Plan, um mehr Websites hinzuzufügen. %1$sJetzt upgraden%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Diese Website ist bereits unter einer kostenlosen Lizenz aktiviert. Jede Website kann nur eine kostenlose Lizenz verwenden.','An error occurred, please try again.'=>'Es ist ein Fehler aufgetreten. Bitte versuche es erneut.','You have successfully activated your license'=>'Du hast deine Lizenz erfolgreich aktiviert','Others'=>'Andere','Restrict by Language'=>'Nach Sprache einschränken','Exclude from Language'=>'Aus Sprache ausschliessen','Restrict element to language'=>'Element auf Sprache einschränken','Show this element only in one language.'=>'Dieses Element nur in einer Sprache anzeigen.','Enable translation'=>'Übersetzung aktivieren','Allow translation to the corresponding language only if the content is written in the default language.'=>'Lässt die Übersetzung in die entsprechende Sprache nur zu, wenn der Inhalt in der Standardsprache verfasst ist.','Select language'=>'Sprache auswählen','Choose in which language to show this element.'=>'Wähle, in welcher Sprache dieses Element angezeigt werden soll.','Exclude element from language'=>'Element aus Sprache ausschliessen','Exclude this element from specific languages.'=>'Dieses Element aus bestimmten Sprachen ausschliessen.','Select languages'=>'Sprachen auswählen','Choose from which languages to exclude this element.'=>'Wähle, aus welchen Sprachen dieses Element ausgeschlossen werden soll.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Dieses Element bleibt sichtbar, wenn die Website über den Übersetzungs-Editor übersetzt wird.','The content of this element should be written in the default language.'=>'Der Inhalt dieses Elements sollte in der Standardsprache verfasst sein.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> ist auf SQL-Fehler gestossen. <a href="%s" title="View TranslatePress SQL Errors">Fehler ansehen</a>.','Automatic translation has been disabled.'=>'Automatische Übersetzung wurde deaktiviert.','Dismiss this notice.'=>'Diesen Hinweis ausblenden.','Logged errors'=>'Protokollierte Fehler','These are the most recent 5 errors logged by TranslatePress:'=>'Dies sind die letzten 5 von TranslatePress protokollierten Fehler:','Yes'=>'Ja','Why are these errors occuring'=>'Warum treten diese Fehler auf','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Falls TranslatePress bei der Ausführung von Abfragen auf deiner Datenbank ein Problem feststellt, kann die Funktion für automatische Übersetzung deaktiviert werden, um zusätzliche Kosten bei Google/DeepL zu vermeiden. Die automatische Übersetzung muss manuell wieder aktiviert werden, nachdem du die Probleme behoben hast.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Die festgestellten SQL-Fehler können aus verschiedenen Gründen auftreten, darunter fehlende Tabellen, fehlende Berechtigungen für den SQL-Benutzer zum Erstellen von Tabellen oder Durchführen anderer Operationen, Probleme nach einer Website-Migration oder Änderungen an der SQL-Server-Konfiguration.','What you can do in this situation'=>'Was du in dieser Situation tun kannst','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Gehe zu Einstellungen -> TranslatePress -> Reiter Allgemein und speichere die Einstellungen. Dadurch werden die Tabellen mit deinen aktuellen SQL-Einstellungen neu generiert. Überprüfe, ob beim Aufrufen deiner Website in einer übersetzten Sprache keine weiteren Fehler auftreten. Achte auf die Zeitstempel der Fehler, um sicherzustellen, dass es sich nicht um alte Fehler handelt. Es werden nur die 5 neuesten Fehler angezeigt.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Falls dein Problem nicht gelöst ist, versuche die folgenden Schritte:','Create a backup of your database'=>'Erstelle ein Backup deiner Datenbank','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Erstelle eine Kopie jeder Übersetzungstabelle, in der du Fehler feststellst. Du kannst die Tabelle innerhalb derselben Datenbank kopieren (zum Beispiel trp_dictionary_en_us_es_es_COPY) -- führe diesen Schritt nur aus, wenn du die aktuellen Übersetzungen behalten möchtest.','Remove the trouble tables by executing the DROP function on them'=>'Entferne die problematischen Tabellen, indem du die DROP-Funktion auf sie anwendest.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Gehe zu Einstellungen -> TranslatePress -> Reiter Allgemein und speichere die Einstellungen. Dadurch werden die Tabellen mit deinem aktuellen SQL-Server neu generiert.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopiere den relevanten Inhalt aus den duplizierten Tabellen (zum Beispiel trp_dictionary_en_us_es_es_COPY) in die neu generierte Tabelle (trp_dictionary_en_us_es_es) -- führe diesen Schritt nur aus, wenn du die aktuellen Übersetzungen behalten möchtest.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Teste es, um zu sehen, ob alles funktioniert. Falls etwas schiefgegangen ist, kannst du das Backup wiederherstellen, das du im ersten Schritt erstellt hast. Überprüfe, ob beim Aufrufen deiner Website in einer übersetzten Sprache keine weiteren Fehler auftreten. Achte auf die Zeitstempel der Fehler, um sicherzustellen, dass es sich nicht um alte Fehler handelt. Es werden nur die 5 neuesten Fehler angezeigt.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Falls dein Problem immer noch nicht gelöst ist, frage deinen Hosting-Anbieter nach den Fehlern. Das häufigste Problem ist fehlende Berechtigungen für den SQL-Benutzer, wie zum Beispiel die Berechtigung zum Erstellen von Tabellen.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Konnte nicht installiert werden. Versuche es erneut über die <a href="%s" >Plugin-Übersicht.</a>','Active'=>'Aktiv','Permission denied.'=>'Zugriff verweigert.','Invalid nonce.'=>'Ungültiges nonce.','Settings scope unknown.'=>'Einstellungsbereich unbekannt.','Legacy disabled.'=>'Legacy deaktiviert.','Language Switcher'=>'Sprachumschalter','Change language to %s'=>'Sprache auf %s ändern','Automatic Translation'=>'Automatische Übersetzung','DeepL'=>'DeepL','Unsupported languages'=>'Nicht unterstützte Sprachen','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Die ausgewählte automatische Übersetzungs-Engine unterstützt diese Sprachen nicht.<br>Du kannst Seiten in diesen Sprachen weiterhin manuell mit dem Übersetzungseditor übersetzen.','API key validation failed.'=>'API-Schlüssel-Validierung fehlgeschlagen.','API key verification was successful.'=>'API-Schlüssel-Verifizierung war erfolgreich.','Please enter your Google Translate key.'=>'Bitte gib deinen Google Translate-Schlüssel ein.','Please enter your DeepL API key.'=>'Bitte gib deinen DeepL API-Schlüssel ein.','Not TranslatePress onboarding page.'=>'Keine TranslatePress-Einrichtungsseite.','Step %s does not exist'=>'Schritt %s existiert nicht.','Welcome'=>'Willkommen','Add Languages'=>'Sprachen hinzufügen','Enable Addons'=>'Erweiterungen aktivieren','Finalize'=>'Abschliessen','Exit Setup'=>'Einrichtung verlassen','Upgrade'=>'Upgrade','Nothing here'=>'Nichts vorhanden','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Deine <strong>TranslatePress</strong>-Lizenz fehlt oder ist ungültig. <br/>Bitte %1$sregistriere deine Kopie%2$s, um automatische Website-Übersetzung via TranslatePress AI, Premium-Addons, automatische Updates und Support zu aktivieren. Brauchst du einen Lizenzschlüssel? %3$sKaufe jetzt einen%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Deine <strong>TranslatePress</strong>-Lizenz läuft am %1$s ab. Bitte %2$sLizenz verlängern%3$s, um weiterhin Zugriff auf automatische Übersetzungen via TP AI, Premium-Addons, Produktdownloads und automatische Updates zu erhalten. %4$sJetzt verlängern%5$s','Error: '=>'Fehler: ','Something went wrong, please try again.'=>'Etwas ist schiefgelaufen, bitte versuche es erneut.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Deine <strong>TranslatePress</strong>-Lizenz ist abgelaufen. <br/>Bitte %1$sLizenz verlängern%2$s, um weiterhin Zugriff auf automatische Übersetzungen via TranslatePress AI, Premium-Addons, Produktdownloads und automatische Updates zu erhalten. %3$sJetzt verlängern %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Lizenzschlüssel stimmt nicht überein. Die eingegebene Lizenz passt nicht zur installierten <strong>%1$s</strong>-Version. <br/>Bitte überprüfe, ob du die korrekte Version für deine Lizenz aus deinem %2$sTranslatePress Account%3$s installiert hast.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Falls du nur das kostenlose Plugin installiert hast, aber eine bezahlte Lizenz hinzugefügt hast, installiere bitte das bezahlte Plugin aus deinem TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Du hast das Aktivierungslimit für deine <strong>%1$s</strong>-Lizenz erreicht. <br/>Verwalte deine aktiven Websites über %2$s deinen Account %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Deine Lizenz ist für diese URL deaktiviert. Reaktiviere sie unter <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Websites verwalten.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Für die automatische Übersetzung mit %1$s ist eine aktive Lizenz erforderlich. Bitte %2$sverlängere%3$s deine Lizenz oder kaufe eine neue %4$shier%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Bitte %1$sgib%2$s deinen Lizenzschlüssel ein, um die automatische Übersetzung von %3$s zu aktivieren.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Du hast weniger als 5.000 TranslatePress AI-Wörter übrig. Um deine Website weiterhin automatisch zu übersetzen, bitte %skaufe zusätzliche AI-Wörter vergünstigt über deinen Account%s.',' Error: '=>' Fehler: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Diese Website ist bereits unter einer kostenlosen Lizenz aktiviert. Jede Website kann nur eine kostenlose Lizenz verwenden. Bitte upgrade zu einem Premium-Plan für mehr TranslatePress AI-Wörter über %1$s deinen Account %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Du hast keine gültige Lizenz für <strong>TranslatePress</strong>. %1$sKostenlos erhalten%2$s, um Zugriff auf TranslatePress AI zu erhalten.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NEU:</strong> Das <strong>Different Domain per Language</strong>-Add-on ist da! Steigere dein globales SEO und schaffe ein lokales Erlebnis mit länderspezifischen Domains wie .de oder .fr. Upgrade zu <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business oder Developer</a>, um darauf zuzugreifen und weitere Premium-Vorteile zu erhalten!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NEU:</strong> Das <strong>Different Domain per Language</strong>-Add-on ist da! Steigere dein globales SEO und schaffe ein lokales Erlebnis mit länderspezifischen Domains wie .de oder .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Mehr erfahren</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Das tägliche Kontingent an Zeichen für die Maschinenübersetzung wurde überschritten. Bitte überprüfe die Seite <strong>TranslatePress -> <a href="%s">Automatische Übersetzung</a></strong> für weitere Informationen.','Marketing optin'=>'Marketing-Opt-in','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Zustimmung zu Benachrichtigungen über Sicherheits- und Funktionsupdates sowie zu nicht-sensiblem Diagnose-Tracking.','TranslatePress Preferred User Language'=>'Bevorzugte TranslatePress-Benutzersprache','Preferred language to navigate the site'=>'Bevorzugte Sprache zum Navigieren auf der Website','The language is automatically set based by the last visited language by the user.'=>'Die Sprache wird automatisch basierend auf der zuletzt vom Benutzer besuchten Sprache festgelegt.','Always use this language'=>'Diese Sprache immer verwenden','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Wenn Sie diese Einstellung aktivieren, bleibt die bevorzugte Sprache die oben ausgewählte und kann im Frontend nicht geändert werden.<br>Diese Sprache wird für verschiedene Vorgänge verwendet, z. B. beim Senden von E-Mails an den Benutzer.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Hallo! Es scheint, als ob Sie <strong>TranslatePress</strong> seit einiger Zeit zum Übersetzen Ihrer Website verwenden. Das ist grossartig! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Wenn Sie sich einen Moment Zeit nehmen könnten, um es auf WordPress.org zu bewerten, würde uns das sehr helfen (und meine Motivation steigern).','~ Razvan, developer of TranslatePress'=>'~ Razvan, Entwickler von TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'TranslatePress auf der Plugin-Seite von WordPress.org bewerten','Ok, I will gladly help!'=>'OK, ich helfe gerne!','No, thanks.'=>'Nein, danke.','Full Language Names'=>'Vollständige Sprachnamen','Short Language Names'=>'Kurze Sprachnamen','Flags with Full Language Names'=>'Flaggen mit vollständigen Sprachnamen','Flags with Short Language Names'=>'Flaggen mit kurzen Sprachnamen','Only Flags'=>'Nur Flaggen','Full Language Names No HTML'=>'Vollständige Sprachnamen ohne HTML','Bottom Right'=>'Unten rechts','Bottom Left'=>'Unten links','Top Right'=>'Oben rechts','Top Left'=>'Oben links','Dark'=>'Dunkel','Light'=>'Hell','Deactivate'=>'Deaktivieren','Activate'=>'Aktivieren','Invalid language code. Please try again.'=>'Ungültiger Sprachcode. Bitte versuche es erneut.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Sprachcodes dürfen nur die Zeichen A-Z a-z 0-9 - _ enthalten. Überprüfe deine Sprachcodes in den Allgemeinen Einstellungen von TranslatePress.','Error! Duplicate URL slug values.'=>'Fehler! Doppelte URL-Slug-Werte.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Du kannst nicht zwei Sprachen auswählen, die denselben <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">ISO-Code</a> haben, aber unterschiedliche Höflichkeitsformen, da dies zu doppelten <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang-Tags</a> führt.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Doppelte Sprache erkannt.<br>Jede Sprache kann nur einmal hinzugefügt werden, um eine korrekte Übersetzungsverwaltung zu gewährleisten.<br> Bitte ändere den doppelten Spracheintrag und versuche es erneut. ','Current Language'=>'Aktuelle Sprache','Opposite Language'=>'Andere Sprache','General'=>'Allgemein','Translate Site'=>'Website übersetzen','Addons'=>'Erweiterungen','License'=>'Lizenz','Settings'=>'Einstellungen','Activate License'=>'Lizenz aktivieren','Pro Features'=>'Pro-Funktionen','Need Help?'=>'Hilfe benötigt?','Recent community discussions'=>'Aktuelle Community-Diskussionen','Loading...'=>'Laden...','Unable to load forum posts'=>'Forenbeiträge können nicht geladen werden.','Ask a Question'=>'Frage stellen','View All Topics'=>'Alle Themen anzeigen','by'=>'von','Have a question?'=>'Hast du eine Frage?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Erhalte direkt Hilfe von den Plugin-Entwicklern, schlage Verbesserungen vor oder teile dein Feedback!','Tip for faster help:'=>'Tipp für schnellere Hilfe:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Beschreibe, was du versucht hast, was du erwartet hast und was passiert ist. Screenshots helfen!','Toggle support chat'=>'Support-Chat ein-/ausblenden','Ask the community'=>'An die Community wenden','Close'=>'Schliessen','Empty feed response'=>'Leere Feed-Antwort','Unable to parse feed'=>'Feed kann nicht verarbeitet werden','Just now'=>'Gerade eben','%d hour ago'=>'vor %d Stunde' . "\0" . 'vor %d Stunden','%d day ago'=>'vor %d Tag' . "\0" . 'vor %d Tagen','Source'=>'Quelle','Srcset'=>'Srcset','Alt attribute'=>'Alt-Attribut','Title attribute'=>'Titel-Attribut','Anchor link'=>'Anker-Link','Placeholder attribute'=>'Platzhalter-Attribut','Submit attribute'=>'Submit-Attribut','Text'=>'Text','Video Poster'=>'Video-Poster','plural form'=>'Pluralform','one'=>'Singular','few'=>'Wenige','many'=>'Viele','other'=>'Andere','Saved'=>'Gespeichert','Save'=>'Speichern','Saving translation...'=>'Übersetzung wird gespeichert...','You have unsaved changes!'=>'Du hast ungespeicherte Änderungen!','Discard changes'=>'Änderungen verwerfen','Discard All'=>'Alle verwerfen','Loading Strings...'=>'Strings werden geladen...','Select string to translate...'=>'String zum Übersetzen auswählen...','Close Editor'=>'Editor schliessen','From'=>'Von','To'=>'Zu','Add Media'=>'Medien hinzufügen','Other languages'=>'Andere Sprachen','Context'=>'Kontext','View Website As'=>'Website anzeigen als','Available in our Pro Versions'=>'Verfügbar in unseren Pro-Versionen','Select or Upload Media'=>'Medien auswählen oder hochladen','Use this media'=>'Dieses Medium verwenden','Translate'=>'Übersetzen','Translate entire block element'=>'Gesamtes Blockelement übersetzen','Split block to translate strings individually'=>'Block aufteilen, um Strings einzeln zu übersetzen','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Änderungen an der Übersetzung speichern. Tastenkürzel: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Zum nächsten String in der Dropdown-Liste navigieren. Tastenkürzel: CTRL(⌘) + ALT + Rechte Pfeiltaste','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Zum vorherigen String in der Dropdown-Liste navigieren. Tastenkürzel: CTRL(⌘) + ALT + Linke Pfeiltaste','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Alle Änderungen verwerfen. Tastenkürzel: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Änderungen in diesem Textfeld verwerfen. Um Änderungen in allen Textfeldern zu verwerfen, Tastenkürzel: CTRL(⌘) + ALT + Z verwenden','Dismiss tooltip'=>'Tooltip schliessen','Quick Intro'=>'Kurze Einführung','Are you sure you want to split this phrase into smaller parts?'=>'Bist du sicher, dass du diese Phrase in kleinere Teile aufteilen möchtest?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Dieser String ist noch nicht für die Übersetzung bereit.<br>Versuche es in einem Moment erneut...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Damit diese Option funktioniert, aktualisiere bitte das Browse as other role Add-on auf die neueste Version.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Um Slugs zu übersetzen, aktualisiere bitte das SEO Pack Add-on auf die neueste Version.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Du kannst eine neue Sprache unter <a href="%s">Einstellungen->TranslatePress</a> hinzufügen.','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Du kannst jedoch weiterhin TranslatePress verwenden, um <strong style="background: #f5fb9d;">Gettext-Strings</strong> auf deiner Seite zu ändern.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Vom Benutzer erstellte Strings können nicht geändert werden, nur jene aus Themes und Plugins.','Extra Translation Features'=>'Zusätzliche Übersetzungsfunktionen','Support for 130+ Extra Languages'=>'Unterstützung für 130+ zusätzliche Sprachen','Access to TranslatePress AI'=>'Zugriff auf TranslatePress AI','Translate SEO Title, Description, Slug'=>'SEO-Titel, Beschreibung und Slug übersetzen','Publish only when translation is complete'=>'Nur veröffentlichen, wenn die Übersetzung vollständig ist','Translate by Browsing as User Role'=>'Übersetzen durch Browsen als Benutzerrolle','Different Menu Items for each Language'=>'Unterschiedliche Menüpunkte für jede Sprache','Automatic User Language Detection'=>'Automatische Erkennung der Benutzersprache','Upgrade to PRO'=>'Auf PRO upgraden','Upgrade to PRO with our biggest discount of the year!'=>'Auf PRO upgraden mit unserem grössten Rabatt des Jahres!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Diesen Black Friday erhältst du Zugriff auf diese Funktionen und mehr zu einem Bruchteil der Kosten:','No available suggestions'=>'Kei Vorschläg verfüegbar','Suggestions from translation memory'=>'Vorschläg us em Übersetzigsspeicher','Click to Copy'=>'Zum Kopiere klicke','Human Translation'=>'Menschlechi Übersetzig','Machine Translation'=>'Maschinelli Übersetzig','Text on this page is %s% translated into all languages.'=>'Dr Text uf dere Syte isch zu %s% i alli Sproche übersetzt.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% vum Text uf dere Syte isch i %2$s übersetzt.','This page is %1$s% translated into %2$s.'=>'Die Syte isch zu %1$s% i %2$s übersetzt.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Der Slug, den du zu bearbeiten versuchst, ist in anderen Slug-Typen vorhanden:%s%. Wenn du ihn bearbeitest, wird jedes Vorkommen ersetzt, unabhängig vom aktuellen Typ.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Fahr mit em Mäus über en Text uf der Syte, klick uf %s,<br> und bearbeit d Übersetzig in der Sytegleiste.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Vergiss nöd, d Übersetzig z speichere. Nutz d Tastaturchurzwäg CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Wechs d Sproch, um d Übersetzigänderige diräkt uf der Syte z gseh.','Search for any text in this page in the dropdown.'=>'Suech im Dropdown nach emene beliebige Text uf dere Syte.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Dini %s-Lizenz isch <span class="trp-license-status-emphasized">abglaufe</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Bitte erneuer dini Lizenz, um wiiterhin Zuegriff uf TranslatePress AI, Premium-Addons, automatisch Updates und Support z ha.','Renew Now'=>'Jetzt erneuere','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Erneuer dini Lizenz an däm Black Friday zu eme spezielle Priis</strong>, um wiiterhin Zuegriff uf Produkt-Downloads, automatisch Updates und Support z ha.','Get Deal'=>'Deal sichere','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Dini %s-Lizenz isch <span class="trp-license-status-emphasized">zruggerstatte</span> worde.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Bitte kauf e neui Lizenz, um wiiterhin Zuegriff uf TranslatePress AI, Premium-Addons, automatisch Updates und Support z ha.','Purchase a new license'=>'Neue Lizenz erwerben','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Deine %s-Lizenz ist <span class="trp-license-status-emphasized">fehlend oder ungültig</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Bitte gib eine gültige Lizenz ein, um Zugriff auf TranslatePress AI, Premium-Addons, automatische Updates und Support zu erhalten. Brauchst du einen Lizenzschlüssel? %1$sJetzt erwerben%2$s','Enter a valid license'=>'Gültige Lizenz eingeben','Slugs'=>'Slugs','Meta Information'=>'Meta-Informationen','String List'=>'String-Liste','Gettext Strings'=>'Gettext-Strings','Images'=>'Bilder','Videos'=>'Videos','Audios'=>'Audios','Dynamically Added Strings'=>'Dynamisch hinzugefügte Strings','Translation Editor'=>'Übersetzungseditor','Edit translations by visually selecting them on each site page'=>'Bearbeite Übersetzungen, indem du sie auf jeder Seite visuell auswählst.','String Translation'=>'String-Übersetzung','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'URL-Slug-Übersetzungen, Plugin- und Theme-Übersetzungen (E-Mails, Formulare usw.) bearbeiten','Current User'=>'Aktueller Benutzer','Logged Out'=>'Abgemeldet','Translate Page'=>'Seite übersetzen','Add a New Language'=>'Neue Sprache hinzufügen','Get a Free AI License'=>'Kostenlose AI-Lizenz erhalten','Your License is Invalid'=>'Deine Lizenz ist ungültig','Get More AI Words (%d left)'=>'Mehr AI-Wörter erhalten (%d übrig)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Öffnet den Beitrag im Übersetzungseditor. Der Beitrag muss vorher als Entwurf gespeichert oder veröffentlicht sein.','Security check'=>'Sicherheitsprüfung','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Warnung:</strong> Einige Zeichenketten enthalten möglicherweise falsch kodierte Zeichen. Dies kann dazu führen, dass Abfragen fehlschlagen und die Seite im Live-Modus nicht übersetzt wird. Überarbeite die folgenden Zeichenketten oder deren Ausgabemethode.','TranslatePress data update'=>'TranslatePress-Datenaktualisierung','We need to update your translations database to the latest version.'=>'Wir müssen deine Übersetzungsdatenbank auf die neueste Version aktualisieren.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Das Aktualisieren ermöglicht, Übersetzungen von lokalisiertem Text aus Plugins und Theme zu bearbeiten. Vorhandene Übersetzungen funktionieren weiterhin wie erwartet.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'WICHTIG: Es wird dringend empfohlen, zuerst eine Sicherungskopie der Datenbank zu erstellen!
Bist du sicher, dass du fortfahren möchtest?','Run the updater'=>'Updater ausführen','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Das Update ermöglicht die Bearbeitung von Übersetzungen für URL-Kennungen. Die bestehende Übersetzung funktioniert weiterhin wie erwartet.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Bitte aktiviere das SEO Addon unter <br/>WordPress -> Einstellungen -> TranslatePress -> Addons-Bereich','Go to Addons'=>'Zu den Addons','The SEO Pack add-on allows translation of all the URL slugs:'=>'Das Add-on SEO Pack ermöglicht die Übersetzung aller URL-Kennungen:','Taxonomy slugs'=>'Taxonomie-Kennungen','Term slugs'=>'Begriffs-Kennungen','Post slugs (this includes pages and custom post types)'=>'Beitrags-Kennungen (dies umfasst Seiten und benutzerdefinierte Beitragstypen)','Post type base slugs'=>'Basis-Kennungen für Beitragstypen','WooCommerce slugs'=>'WooCommerce-Kennungen','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Das SEO Pack Add-on ist in ALLEN Premium-Versionen des Plugins verfügbar.','Upgrade to Pro'=>'Auf Pro upgraden','Description'=>'Beschreibung','Article Section'=>'Artikelabschnitt','Article Tag'=>'Artikel-Tag','OG Title'=>'OG-Titel','OG Site Name'=>'OG-Site-Name','OG Description'=>'OG-Beschreibung','OG Image Alt'=>'OG-Bild-Alt-Text','Twitter Title'=>'Twitter-Titel','Twitter Description'=>'Twitter-Beschreibung','Twitter Image Alt'=>'Twitter-Bild-Alt-Text','Page Title'=>'Seitentitel','Dublin Core Title'=>'Dublin-Core-Titel','Dublin Core Description'=>'Dublin-Core-Beschreibung','OG Image'=>'OG-Bild','OG Image Secure URL'=>'OG-Bild-Secure-URL','Twitter Image'=>'Twitter-Bild','Removing cdata dictionary strings for language %s...'=>'Entferne CDATA-Dictionary-Zeichenketten für Sprache %s...','Removing untranslated dictionary links for language %s...'=>'Entferne unübersetzte Wörterbuch-Links für Sprache %s...','Removing duplicated gettext strings for language %s...'=>'Entferne doppelte Gettext-Zeichenketten für Sprache %s...','Removing duplicated dictionary strings for language %s...'=>'Entferne doppelte Dictionary-Zeichenketten für Sprache %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Entferne nicht übersetzte Dictionary-Zeichenketten, für die eine Übersetzung für Sprache %s verfügbar ist...','Inserting original strings for language %s...'=>'Füge Original-Zeichenketten für Sprache %s ein...','Cleaning original strings table for language %s...'=>'Bereinige Tabelle der Original-Zeichenketten für Sprache %s...','Updating original string ids for language %s...'=>'Aktualisiere IDs der Original-Zeichenketten für Sprache %s...','Regenerating original meta table for language %s...'=>'Erstelle Original-Meta-Tabelle für Sprache %s neu...','Cleaning original meta table for language %s...'=>'Bereinige Original-Meta-Tabelle für Sprache %s...','Replacing original id NULL with value for language %s...'=>'Ersetze Original-ID NULL durch Wert für Sprache %s...','Inserting gettext original strings for language %s...'=>'Füge Gettext-Original-Zeichenketten für Sprache %s ein...','Cleaning gettext original strings table for language %s...'=>'Bereinige Tabelle der Gettext-Original-Zeichenketten für Sprache %s...','Updating gettext original string ids for language %s...'=>'Aktualisiere IDs der Gettext-Original-Zeichenketten für Sprache %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Migriere Basis-Kennungen für Taxonomien und Beitragstypen zur neuen Tabellenstruktur...','Migrating post slugs to new table structure for language %s...'=>'Migriere Beitrags-Kennungen zur neuen Tabellenstruktur für Sprache %s...','Migrating term slugs to new table structure for language %s...'=>'Migriere Begriff-Slugs in die neue Tabellenstruktur für die Sprache %s...','Finishing up...'=>'Fertigstellen...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Die Datenbankoptimierung wurde nicht erfolgreich abgeschlossen. Wir empfehlen, die Originaldatenbank wiederherzustellen oder <a href="%s" >es erneut zu versuchen.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Update abgebrochen! Dein Benutzerkonto verfügt nicht über die Berechtigung, Datenbank-Updates durchzuführen.','Update aborted! Invalid nonce.'=>'Update abgebrochen! Ungültiger nonce.','Update aborted! Incorrect action.'=>'Update abgebrochen! Falsche Aktion.','Update aborted! Incorrect language code.'=>'Update abgebrochen! Falscher Sprachcode.','Updating database to version %s+'=>'Datenbank wird auf Version %s+ aktualisiert','Processing table for language %s...'=>'Tabelle für Sprache %s wird verarbeitet...','Back to TranslatePress Settings'=>'Zurück zu den TranslatePress-Einstellungen','Successfully updated database!'=>'Datenbank erfolgreich aktualisiert!',' done.'=>' fertig.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Alle einzelnen TranslatePress-Add-on-Plugins <a href="%1$s" target="_blank">wurden eingestellt</a> und sind jetzt in den Premium-Versionen Personal, Business und Developer von TranslatePress enthalten. Bitte melde dich auf deiner <a href="%2$s" target="_blank">Kontoseite</a> an, lade die neue Premium-Version herunter und installiere sie. Deine individuellen Add-on-Einstellungen werden übernommen.','Brand-new Language Switcher Settings are here!'=>'Brandneue Sprachumschalter-Einstellungen sind da!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Erkunde vorgefertigte Vorlagen, wechsle Farben, Flaggenstile, Abstände, Layouts und mehr. Nutze die Live-Vorschau, um deinen Sprachumschalter in Sekundenschnelle zu verfeinern.','Start customizing'=>'Jetzt anpassen','Read documentation'=>'Dokumentation lesen','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> benötigt die <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP-Bibliothek</a></strong>. Bitte kontaktiere deinen Server-Administrator, um diese auf deinem Server zu installieren.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Einschränkung für lange Abfragen bei WPEngine-Hosting erkannt. Einige grosse Seiten könnten unübersetzt erscheinen. Du kannst die Einschränkung aufheben, indem du Folgendes zur wp-config.php deiner Website hinzufügst: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Benutzerdefinierte Sprachflagge','The Language code of the added custom language cannot be empty.'=>'Der Sprachcode der hinzugefügten benutzerdefinierten Sprache darf nicht leer sein.','The Language code of the added custom language is invalid.'=>'Der Sprachcode der hinzugefügten benutzerdefinierten Sprache ist ungültig.','The Automatic Translation Code of the added custom language is invalid.'=>'Der Code für die automatische Übersetzung der hinzugefügten benutzerdefinierten Sprache ist ungültig.','TranslatePress Add-ons'=>'TranslatePress-Add-ons','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Du musst zuerst diese Version kaufen, um Zugriff auf das Add-on %1$shier%2$s zu haben.','Please %1$senter your license%2$s key first, to activate this addon.'=>'Bitte %1$sgib deinen Lizenzschlüssel%2$s zuerst ein, um dieses Addon zu aktivieren.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Du brauchst eine aktive Lizenz, um Zugriff auf das Addon zu haben. Erneuere oder kaufe eine neue Lizenz %1$shier%2$s.','Advanced Add-ons'=>'Erweiterte Add-ons','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Diese Add-ons erweitern dein Übersetzungs-Plugin und sind in den Developer-, Business- und Personal-Plänen verfügbar.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Legacy)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'SEO-Unterstützung für Seiten-Slug, Seitentitel, Beschreibung sowie Facebook- und Twitter-Social-Graph-Informationen. Das HTML-lang-Attribut wird korrekt gesetzt.','Multiple Languages'=>'Mehrere Sprachen','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Füge so viele Sprachen hinzu, wie du für dein Projekt brauchst, um global zu werden. Veröffentliche deine Sprache erst, wenn alle Übersetzungen fertig sind.','Pro Add-ons'=>'Pro-Add-ons','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Diese Add-ons erweitern dein Übersetzungs-Plugin und sind in den Business- und Developer-Plänen verfügbar.','DeepL Automatic Translation'=>'Automatische DeepL-Übersetzung','Automatically translate your website through the DeepL API.'=>'Übersetze deine Website automatisch über die DeepL API.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Fordert Besucher auf, basierend auf ihren Browsereinstellungen oder ihrer IP-Adresse zu ihrer bevorzugten Sprache zu wechseln, und merkt sich die zuletzt besuchte Sprache.','Translator Accounts'=>'Übersetzer-Konten','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Erstelle Übersetzer-Konten für neue Benutzer oder erlaube bestehenden Benutzern, die keine Administratoren sind, deine Website zu übersetzen.','Browse As User Role'=>'Als Benutzerrolle durchsuchen','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Navigiere deine Website genau so, wie es eine bestimmte Benutzerrolle tun würde. Wirklich nützlich für dynamische Inhalte oder versteckte Inhalte, die für bestimmte Benutzer angezeigt werden.','Navigation Based on Language'=>'Sprachbasierte Navigation','Configure different menu items for different languages.'=>'Konfiguriere verschiedene Menüeinträge für verschiedene Sprachen.','Different Domain per Language'=>'Unterschiedliche Domain pro Sprache','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Verbinde separate Domains oder Subdomains mit jeder deiner übersetzten Versionen. Stärke die lokale Identität deiner Marke und verbessere die SEO-Leistung für jede Sprache, die du unterstützt.','Recommended Plugins'=>'Empfohlene Plugins','A short list of plugins you can use to extend your website.'=>'Eine kurze Liste von Plugins, mit denen du deine Website erweitern kannst.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Erfasse mehr Benutzerinformationen im Registrierungsformular mithilfe benutzerdefinierter Profilfelder von Profile Builder und/oder füge einen E-Mail-Bestätigungsprozess hinzu, um die Kundenkonten zu verifizieren.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Akzeptiere Zahlungen von Benutzern, erstelle Abonnementpläne und schränke Inhalte auf deiner Mitgliedschafts-Website ein.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Erstelle No-Code-Automatisierungen und Workflows auf deiner WordPress-Website. Verbinde deine Plugins, Websites und Apps ganz einfach miteinander.','Save Changes'=>'Änderungen speichern','TranslatePress Errors'=>'TranslatePress-Fehler','There are no logged errors.'=>'Es sind keine Fehler protokolliert.','Change language'=>'Sprache ändern','Website language selector'=>'Sprachauswahl der Website','WordPress Translation Plugin'=>'WordPress-Übersetzungsplugin','Available languages'=>'Verfügbare Sprachen','Language Switcher update notice'=>'Hinweis zum Language-Switcher-Update','Legacy language switcher is currently enabled'=>'Der Legacy Language Switcher ist aktuell aktiviert','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Wir haben den Switcher für mehr Anpassungsmöglichkeiten und ein besseres Benutzererlebnis aktualisiert.<br>Um den neuen Konfigurator zu verwenden, schalte <strong>Legacy Language Switcher laden</strong> aus.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Hinweis: Du kannst dies jederzeit unter <strong>Erweiterte Einstellungen → <a href="%s">Fehlerbehebung</a></strong> rückgängig machen.','Enable the new switcher'=>'Neuen Switcher aktivieren','Your License Key is valid.'=>'Dein Lizenzschlüssel ist gültig.','Your License Key is invalid.'=>'Dein Lizenzschlüssel ist ungültig.','Your License has expired.'=>'Deine Lizenz ist abgelaufen.','Deactivate License'=>'Lizenz deaktivieren','Add a license key'=>'Lizenzschlüssel hinzufügen','License Key'=>'Lizenzschlüssel','Manage your license in your %1$s.'=>'Verwalte deine Lizenz auf deiner %1$s.','Account Page'=>'Kontoseite','Don’t have a TranslatePress AI License Key?'=>'Du hast keinen TranslatePress AI-Lizenzschlüssel?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Du kannst einen %1$sgratis%2$s bekommen, indem du ein kostenloses Konto erstellst. Enthalten sind:','Access to TranslatePress AI for instant automatic translations'=>'Zugriff auf TranslatePress AI für sofortige automatische Übersetzungen','2000 AI words to translate automatically'=>'2000 AI-Wörter für automatische Übersetzungen','Get a free License Today'=>'Hole dir heute eine kostenlose Lizenz','Debug Information'=>'Debug-Informationen','Debug Data for License Checking'=>'Debug-Daten für die Lizenzprüfung','Debug Data for License Activation'=>'Debug-Daten für die Lizenzaktivierung','Get more AI words and unlock all features with TranslatePress Pro.'=>'Erhalte mehr AI-Wörter und schalte alle Funktionen mit TranslatePress Pro frei.','Upgrade now ↗'=>'Jetzt upgraden ↗','Already purchased a Premium version?'=>'Hast du schon eine Premium-Version gekauft?','Go to your %1$s'=>'Gehe zu deinem %1$s','TranslatePress.com Account'=>'TranslatePress.com-Konto','Download & Install the Pro plugin'=>'Pro-Plugin herunterladen und installieren','Learn More'=>'Mehr erfahren','Get a translation volume estimate with a detailed breakdown per page'=>'Eine Schätzung des Übersetzungsvolumens mit detaillierter Aufschlüsselung pro Seite erhalten','Find how many translatable words are on your website'=>'Finde heraus, wie viele übersetzbare Wörter auf deiner Website sind','Enable Automatic Translation'=>'Automatische Übersetzung aktivieren','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Um <strong>DeepL</strong> für die automatische Übersetzung zu nutzen, aktiviere diese Pro-Erweiterung unter <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Die automatische Übersetzung mit <strong>DeepL</strong> ist als <a href="%1$s" target="_blank" title="%2$s">%2$s</a> verfügbar.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Durch ein Upgrade erhältst du Zugriff auf alle kostenpflichtigen Erweiterungen, Premium-Support und hilfst, die zukünftige Entwicklung von TranslatePress zu finanzieren.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Bitte beachte, dass die Nutzung der DeepL API separat bezahlt wird. Siehe <a href="https://www.deepl.com/pro.html#developer">DeepL Preisinformationen</a>.','TranslatePress Pro Add-ons'=>'TranslatePress Pro-Erweiterungen','Test API credentials'=>'API-Zugangsdaten testen','Check if the selected translation engine is configured correctly.'=>'Prüfen, ob die ausgewählte Übersetzungs-Engine korrekt konfiguriert ist.','Alternative Engines'=>'Alternative Übersetzungs-Engines','Switch to TranslatePress AI'=>'Zu TranslatePress AI wechseln','Integrate machine translation directly with your WordPress website.'=>'Maschinelle Übersetzung direkt in deine WordPress-Website integrieren.','More info'=>'Mehr Infos','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Wähle aus, welche Engine du verwenden möchtest, um deine Website %1$s automatisch zu übersetzen.','Automatic Translation Settings'=>'Einstellungen für automatische Übersetzungen','AI Words Low Notification'=>'Benachrichtigung bei niedrigem AI-Wörterbestand','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Sie erhalten eine E-Mail-Benachrichtigung, wenn Ihr TranslatePress AI-Wörterbestand unter den festgelegten Schwellenwert fällt.','This feature is only available when using the TranslatePress AI translation engine.'=>'Diese Funktion ist nur bei Verwendung der TranslatePress AI-Übersetzungsmaschine verfügbar.','Notification Email'=>'Benachrichtigungs-E-Mail','The email address where the low AI words notification will be sent.'=>'Die E-Mail-Adresse, an die die Benachrichtigung bei niedrigem AI-Wörterbestand gesendet wird.','Word Threshold'=>'Schwellenwert','words'=>'Wörter','You will be notified when remaining AI words drop below this number.'=>'Sie werden benachrichtigt, wenn die verbleibenden AI-Wörter unter diese Zahl fallen.','Automatically Translate Slugs'=>'Slugs automatisch übersetzen','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Generiert automatische Übersetzungen von Slugs für Beiträge, Seiten und Custom Post Types.<br/>Die Slugs werden ab dem zweiten Aktualisieren jeder Seite automatisch übersetzt.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Diese Funktion ist nur in der kostenpflichtigen Version verfügbar. Upgraden Sie TranslatePress und schalten Sie weitere Premium-Funktionen frei.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Setzt voraus, dass das <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> installiert und aktiviert ist.','Upgrade now'=>'Jetzt upgraden','Block Crawlers'=>'Crawler blockieren','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Verhindert, dass Crawler automatische Übersetzungen auf Ihrer Website auslösen.<br>Dies hindert Crawler nicht daran, auf die Seiten dieser Website zuzugreifen.','Limit machine translation / characters per day'=>'Maschinelle Übersetzung begrenzen / Zeichen pro Tag','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Legen Sie ein Limit für die Anzahl automatisch übersetzter Zeichen fest, damit Sie Ihr Projekt besser budgetieren können.','characters per day'=>'Zeichen pro Tag','Today\'s Character Count: '=>'Zeichenanzahl heute: ','Log machine translation queries.'=>'Maschinelle Übersetzungsanfragen protokollieren.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Nur für Testzwecke aktivieren. Kann die Leistung beeinträchtigen.<br>Alle Datensätze werden in der Datenbanktabelle wp_trp_machine_translation_log gespeichert. Verwende ein Plugin wie <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a>, um die Protokolle zu durchsuchen, oder direkt über deinen Datenbankmanager (PHPMyAdmin, usw.).','Test API Credentials'=>'API-Zugangsdaten testen','HTTP Referrer: '=>'HTTP-Referrer: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Verwende diesen HTTP-Referrer, wenn die API dir erlaubt, die Schlüsselverwendung über ihr Dashboard einzuschränken.','Response'=>'Antwort','Response Body'=>'Antworttext','Entire Response From wp_remote_get():'=>'Vollständige Antwort von wp_remote_get():','All Languages'=>'Alle Sprachen','Select the languages you wish to make your website available in.'=>'Wähle die Sprachen aus, in denen du deine Website verfügbar machen möchtest.','Formality'=>'Formalebene','Code'=>'Code','Slug'=>'Slug','Default'=>'Standard','Formal'=>'Formell','Informal'=>'Informell','Language'=>'Sprache','This language does not support formality. '=>'Diese Sprache unterstützt keine Formalebene. ','Are you sure you want to remove this language?'=>'Möchtest du diese Sprache wirklich entfernen?','Custom Languages'=>'Benutzerdefinierte Sprachen','To Add more languages activate the Multiple Languages Addon'=>'Aktiviere das Multiple Languages Addon, um weitere Sprachen hinzuzufügen.','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Du benötigst eine aktive Lizenz, um weitere Sprachen hinzuzufügen. Überprüfe in deinem %1$sKonto%2$s, ob deine Lizenz gültig ist.','Please %1$senter your license%2$s key first to add more languages.'=>'Bitte %1$sgib deinen Lizenz%2$s-Schlüssel zuerst ein, um weitere Sprachen hinzuzufügen.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Das Hinzufügen von mehr als zwei Sprachen ist eine kostenpflichtige Funktion. Führe ein Upgrade für TranslatePress durch und schalte weitere Premium-Funktionen frei.','Website Languages'=>'Website-Sprachen','Default Language'=>'Standardsprache','Select the language your content is written in.'=>'Wähle die Sprache aus, in der dein Inhalt verfasst ist.','WARNING. Changing the default language will invalidate existing translations.'=>'WARNUNG. Das Ändern der Standardsprache macht bestehende Übersetzungen ungültig.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Auch ein Wechsel von en_US zu en_GB, da diese als zwei verschiedene Sprachen behandelt werden.','In most cases changing the default flag is all it is needed: '=>'In den meisten Fällen ist das Ändern der Standard-Flagge alles, was nötig ist: ','replace the default flag'=>'Standard-Flagge ersetzen','Re-run Setup Wizard'=>'Setup-Assistenten erneut ausführen','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Der Setup-Assistent ermöglicht es dir, TranslatePress schnell einzurichten. Du kannst ihn jederzeit starten.','Language Settings'=>'Spracheinstellungen','Use Native language name'=>'Nativen Sprachnamen verwenden','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Aktiviere diese Option, wenn du Sprachen in ihren nativen Namen anzeigen möchtest. Andernfalls werden Sprachen auf Englisch angezeigt.','Use a subdirectory for the default language'=>'Unterverzeichnis für die Standardsprache verwenden','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Aktiviere diese Option, wenn du das Unterverzeichnis in der URL für die Standardsprache hinzufügen möchtest.<br/>Wenn du diese Option aktivierst, wird die für Website-Besucher sichtbare Standardsprache die erste in der Liste «Alle Sprachen».','Force language in custom links'=>'Sprache in benutzerdefinierten Links erzwingen','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Wähle «Ja», wenn du möchtest, dass benutzerdefinierte Links ohne Sprachkodierung die aktuell ausgewählte Sprache beibehalten.','Shortcode '=>'shortcode ','Use shortcode on any page or widget.'=>'Verwende shortcode auf jeder Seite oder in jedem Widget.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Du kannst auch den <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> im WP Gutenberg Editor hinzufügen.','Menu item'=>'Menüpunkt','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Gehe zu %1$s Design -> Menüs%2$s, um Sprachen zum Language Switcher in einem beliebigen Menü hinzuzufügen.','Learn more in our documentation.'=>'Erfahre mehr in unserer Dokumentation.','Floating language selection'=>'Schwebende Sprachauswahl','Add a floating dropdown that follows the user on every page.'=>'Ein schwebendes Dropdown hinzufügen, das dem Benutzer auf jeder Seite folgt.','Show "Powered by TranslatePress"'=>'"Powered by TranslatePress" anzeigen','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Das kleine "Powered by TranslatePress"-Label im schwebenden Sprachumschalter anzeigen.','5 Days to Better Multilingual Websites'=>'5 Tage zu besseren mehrsprachigen Websites','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sNimm an unserem KOSTENLOSEN & EXKLUSIVEN Onboarding-Kurs teil%s und lerne, wie du deinen mehrsprachigen Traffic steigerst, internationale Märkte erreichst und Zeit & Geld sparst, während du das Maximum aus TranslatePress herausholst!','Invalid email address'=>'Ungültige E-Mail-Adresse','Your email'=>'Deine E-Mail','Sign me up!'=>'Anmelden!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Melde dich mit deiner E-Mail-Adresse an und erhalte einen 5-teiligen E-Mail-Leitfaden, der dir hilft, das volle Potenzial von TranslatePress auszuschöpfen.','Dismiss email course notification'=>'E-Mail-Kurs-Benachrichtigung verwerfen','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hey %s,<br>Verpasse keine wichtigen Updates mehr – aktiviere Benachrichtigungen zu Sicherheits- und Feature-Updates sowie nicht-sensitives Diagnose-Tracking.','Allow & Continue'=>'Erlauben & Fortfahren','Skip'=>'Überspringen','This will allow TranslatePress to:'=>'Dies ermöglicht TranslatePress:','Your profile overview'=>'Deine Profilübersicht','Name and email address'=>'Name und E-Mail-Adresse','Admin Notices'=>'Admin-Hinweise','Updates, announcements, marketing, no spam'=>'Updates, Ankündigungen, Marketing, kein Spam','Plugin status & settings'=>'Plugin-Status und Einstellungen','Active, Deactivated, installed version and settings'=>'Aktiv, deaktiviert, installierte Version und Einstellungen','Privacy Policy'=>'Datenschutzerklärung','Terms of Service'=>'Nutzungsbedingungen','Support'=>'Support','Documentation'=>'Dokumentation','Add Extra AI Words'=>'Extra AI-Wörter hinzufügen','Optimize TranslatePress database tables'=>'TranslatePress-Datenbanktabellen optimieren','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>WICHTIGER HINWEIS:</strong> Vor dem Ausführen dieser Aktion wird dringend empfohlen, zuerst ein Backup der Datenbank zu erstellen.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'WICHTIG: Es wird dringend empfohlen, zuerst ein Backup der Datenbank zu erstellen!! Bist du sicher, dass du fortfahren möchtest?','Operations to perform'=>'Durchzuführende Operationen','Remove CDATA for original and dictionary strings'=>'CDATA für Original- und Dictionary-Strings entfernen','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Entfernt CDATA aus den Tabellen trp_original_strings und trp_dictionary_*.<br>Dieser Inhaltstyp sollte von TranslatePress nicht erkannt werden. Er könnte in älteren Versionen des Plugins in die Datenbank eingefügt worden sein.','Remove untranslated links from dictionary tables'=>'Unübersetzte Links aus Wörterbuch-Tabellen entfernen','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Entfernt unübersetzte Links und Bilder aus allen trp_dictionary_*-Tabellen. Diese Tabellen enthalten Übersetzungen für benutzereingegebene Strings wie Beitragsinhalt, Beitragstitel, Menüs usw.','Remove duplicate rows for gettext strings'=>'Doppelte Zeilen für Gettext-Strings entfernen','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Bereinigt alle trp_gettext_*-Tabellen von doppelten Zeilen. Diese Tabellen enthalten Übersetzungen für Theme- und Plugin-Strings.','Remove duplicate rows for dictionary strings'=>'Doppelte Zeilen für Dictionary-Strings entfernen','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Bereinigt alle trp_dictionary_*-Tabellen von doppelten Zeilen. Diese Tabellen enthalten Übersetzungen für benutzereingegebene Strings wie Beitragsinhalt, Beitragstitel, Menüs usw.','Remove duplicate rows for original dictionary strings'=>'Doppelte Zeilen für Original-Dictionary-Strings entfernen','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Bereinigt die Tabelle trp_original_strings von doppelten Zeilen. Diese Tabelle enthält Strings in der Standardsprache ohne jede Übersetzung.<br>Die Tabelle trp_original_meta, die Meta-Informationen enthält, die sich auf die ID des übergeordneten Beitrags beziehen, wird ebenfalls neu generiert.<br>Solche Duplikate können in Ausnahmesituationen bei unerwartetem Verhalten auftreten.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Gettext-Strings mit Original-ID NULL durch die korrekten Original-IDs ersetzen','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Behebt ein Edge-Case-Problem, bei dem einige Gettext-Strings die Original-ID fälschlicherweise auf NULL gesetzt haben, was Probleme im Übersetzungs-Editor verursacht.<br>Dieser Vorgang korrigiert die Original-IDs in den trp_gettext_*-Tabellen.<br>Aktiviere diese Option nur, wenn du ein Problem im Übersetzungs-Editor hattest, bei dem das Anklicken des grünen Bleistifts den Gettext-String nicht in der linken Seitenleiste zur Übersetzung angezeigt hat.<br>Andernfalls lass diese Option bitte deaktiviert, da es sich um einen aufwändigen Vorgang handelt.','Optimize Database'=>'Datenbank optimieren','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'TranslatePress-Tabellen werden aktualisiert. Bitte lassen Sie dieses Fenster geöffnet.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Die inaktiven Sprachen sind für den Administrator weiterhin sichtbar und aktiv. Für andere Benutzer sind sie in den Sprachumschaltern nicht sichtbar und auch nicht zugänglich.','unknown'=>'unbekannt','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Extra Languages Add-on</strong> erfordert TranslatePress Version %1$s oder höher. Sie verwenden derzeit Version %2$s. Bitte aktualisieren Sie TranslatePress, um diese Funktion zu aktivieren.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Automatische und manuelle Slug-Übersetzungsänderungen, die durchgeführt wurden, als <strong>TranslatePress - Multilingual</strong> 2.8.4 aktiv war, mussten wegen einiger Probleme mit dieser Version entfernt werden. Alle Slug-Übersetzungen aus der Zeit vor dieser Version sind jetzt in Verwendung. Danke für dein Verständnis!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Falls Sie diese unbedingt benötigen, befinden sich die entfernten Übersetzungen in den Tabellen trp_slug_original_obsolete und trp_slug_translation_obsolete.','View Docs'=>'Dokumentation anzeigen','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Weisen Sie jeder Sprache verschiedene Domains oder Subdomains zu. Wenn Besucher auf diese Domains zugreifen, lädt TranslatePress die entsprechende Sprachübersetzung direkt, ohne umzuleiten.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Beispiel: %1$s für Englisch, %2$s für Spanisch, %3$s für Französisch.','Before enabling:'=>'Vor der Aktivierung:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Stelle sicher, dass deine Domänen registriert sind, auf deinen Server verweisen und SSL-Zertifikate konfiguriert sind.','Domain'=>'Domäne','Map this language to a different domain or sub-domain.'=>'Ordne diese Sprache einer anderen Domäne oder Subdomäne zu.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Mit aktueller Domäne vorausfüllen','Check DNS'=>'DNS überprüfen','Checking DNS...'=>'DNS wird überprüft...','DNS is correctly configured!'=>'DNS ist korrekt konfiguriert!','DNS check failed. Please verify your domain configuration.'=>'DNS-Überprüfung fehlgeschlagen. Bitte überprüfe deine Domänenkonfiguration.','This domain is already assigned to another language.'=>'Diese Domäne ist bereits einer anderen Sprache zugeordnet.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Different Domain per Language Add-on</strong> erfordert TranslatePress Version %1$s oder höher. Du verwendest momentan Version %2$s. Bitte aktualisiere TranslatePress, um diese Funktion zu aktivieren.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Hinweis: Diese Option ist deaktiviert, wenn das Different Domain for Language addon aktiv ist.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: Eine Domäne ist erforderlich, wenn Domain-Mapping aktiviert ist. Der Schalter wurde für Sprachen mit leeren Domänen deaktiviert.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: Dieselbe Domäne kann nicht mehreren Sprachen zugeordnet werden. Der Schalter wurde für doppelte Domänen deaktiviert.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: Eine Sprachdomäne kann nicht dieselbe sein wie die Hauptwebsite-URL. Der Schalter wurde für die übereinstimmende Domäne deaktiviert.','Please enter a domain.'=>'Bitte gib eine Domäne ein.','Invalid domain format.'=>'Ungültiges Domänenformat.','Could not reach domain: %s'=>'Domäne konnte nicht erreicht werden: %s','Domain returned HTTP status %d.'=>'Domäne hat den HTTP-Status %d zurückgegeben.','Domain is reachable!'=>'Domäne ist erreichbar!','Limit this menu item to the following languages'=>'Diesen Menüpunkt auf die folgenden Sprachen beschränken','Date format'=>'Datumsformat','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Das Datumsformat für jede übersetzte Sprache anpassen.<br/>Leer lassen für die standardmässige WP-Einstellung oder weitere Informationen <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">hier</a>.','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Um eine bestehende TranslatePress-Sprache zu bearbeiten, gib den Sprachcode ein und fülle nur die Spalten aus, die du überschreiben möchtest (z. B. Sprachname, Flagge).<br>Du kannst auch neue benutzerdefinierte Sprachen hinzufügen. Diese sind unter Allgemeine Einstellungen, Liste aller Sprachen verfügbar, wo der Slug bearbeitet werden kann.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Für eine benutzerdefinierte Flagge lade zuerst das Bild in die Mediathek hoch und füge dann die URL ein.<br>Das Ändern oder Löschen einer benutzerdefinierten Sprache wirkt sich auf Übersetzungen und Website-URLs aus.<br>Der Sprachcode und der ISO-Code sollten nur Buchstaben, Zahlen, "-" und "_" enthalten.<br>Die ISO-Codes sind auf <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO-Codes</a> und <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Zielcodes</a> zu finden.','Language code'=>'Sprachcode','Language name'=>'Sprachname','Native name'=>'Nativer Name','ISO Code'=>'ISO-Code','Flag URL'=>'Flaggen-URL','Text RTL'=>'RTL-Text','Custom language'=>'Benutzerdefinierte Sprache','Disable dynamic translation'=>'Dynamische Übersetzung deaktivieren','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Deaktiviert die Erkennung von Strings, die dynamisch mittels JavaScript angezeigt werden. <br/>Strings, die über einen serverseitigen AJAX-Aufruf geladen werden, werden weiterhin übersetzt.','Disable translation for gettext strings'=>'Übersetzung für Gettext-Strings deaktivieren','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Gettext-Zeichenketten sind Zeichenketten, die von Themes und Plugins ausgegeben werden. <br> Die Übersetzung dieser Zeichenketten über TranslatePress kann unnötig sein, wenn sie bereits mit dem .po/.mo-Übersetzungsdateisystem übersetzt wurden.<br>Das Aktivieren dieser Option kann in bestimmten Fällen die Seitenladegeschwindigkeit Ihrer Website verbessern. Der Nachteil ist, dass Sie Gettext-Übersetzungen nicht mehr mit TranslatePress bearbeiten können und auch nicht mehr von der automatischen Übersetzung dieser Zeichenketten profitieren können.','Gettext Strings translation is disabled'=>'Die Übersetzung von Gettext-Zeichenketten ist deaktiviert','To enable it go to '=>'Um sie zu aktivieren, gehe zu ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Erweiterte Einstellungen->Debug->Übersetzung für Gettext-Strings deaktivieren',' and uncheck the Checkbox.'=>' und deaktiviere das Kontrollkästchen.','Dismiss'=>'Ausblenden','Exclude translated links from sitemap'=>'Übersetzte Links aus der sitemap ausschliessen','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Übersetzte Links nicht in Sitemaps aufnehmen, die von SEO-Plugins generiert werden.<br/>Erfordert, dass das <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> installiert und aktiviert ist.','Disable post container tags for post title'=>'Container-Tags für Beitragstitel deaktivieren','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Es deaktiviert die Suchindexierung des Beitragstitels in übersetzten Sprachen.<br/>Nützlich, wenn der Titel des Beitrags kein HTML erlaubt und dadurch die Seite zerstört wird.','Disable post container tags for post content'=>'Container-Tags für Beitragsinhalt deaktivieren','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Es deaktiviert die Suchindexierung des Beitragsinhalts in übersetzten Sprachen.<br/>Nützlich, wenn der Inhalt des Beitrags kein HTML erlaubt und dadurch die Seite zerstört wird.','Do not translate certain paths'=>'Bestimmte Pfade nicht übersetzen','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Wähle aus, welche Pfade übersetzt werden können. Unterstützt Wildcards am Ende des Pfads.<br>Um beispielsweise https://example.com/some/path auszuschliessen, kannst du entweder die Regel /some/path/ oder /some/* verwenden.<br>Gib jede Regel in einer eigenen Zeile ein. Um die Startseite auszuschliessen, verwende {home}.','Exclude Paths From Translation'=>'Pfade von der Übersetzung ausschliessen','Translate Only Certain Paths'=>'Nur bestimmte Pfade übersetzen','Enable the hreflang x-default tag for language:'=>'Das hreflang-x-default-Tag für Sprache aktivieren:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Aktiviert hreflang="x-default" für eine ganze Sprache. Weitere Details in der Dokumentation.','Translate numbers and numerals'=>'Zahlen und Ziffern übersetzen','Enable translation of numbers ( e.g. phone numbers)'=>'Übersetzung von Zahlen aktivieren ( z. B. Telefonnummern)','Selector'=>'Selektor','Exclude from dynamic translation'=>'Von der dynamischen Übersetzung ausschliessen','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Zeichenketten, die in HTML-Knoten gefunden werden, die auf diese Selektoren passen, nicht dynamisch übersetzen.<br>Schliesst alle untergeordneten Elemente von HTML-Knoten, die auf diese Selektoren passen, von der Übersetzung mit JavaScript aus.<br/>Diese Zeichenketten werden weiterhin serverseitig übersetzt, falls möglich.','Gettext String'=>'Gettext-Zeichenkette','Exclude Gettext Strings'=>'Gettext-Zeichenketten ausschliessen','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Diese Zeichenketten von der Übersetzung als Gettext-Zeichenketten durch TranslatePress ausschliessen. Domain leer lassen, um jede Gettext-Zeichenkette zu berücksichtigen.<br/>Können weiterhin über po/mo-Dateien übersetzt werden.','Exclude selectors only from automatic translation'=>'Selektoren nur von der automatischen Übersetzung ausschliessen','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Zeichenketten, die in HTML-Knoten gefunden werden, die auf diese Selektoren passen, nicht automatisch übersetzen.<br>Schliesst alle untergeordneten Elemente von HTML-Knoten, die auf diese Selektoren passen, von der automatischen Übersetzung aus.<br>Eine manuelle Übersetzung dieser Zeichenketten ist weiterhin möglich.','Exclude selectors from translation'=>'Selektoren von der Übersetzung ausschliessen','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Zeichenketten, die in HTML-Knoten gefunden werden, die auf diese Selektoren passen, nicht übersetzen.<br>Schliesst alle untergeordneten Elemente von HTML-Knoten, die auf diese Selektoren passen, von der Übersetzung aus.<br>Diese Zeichenketten können weder manuell noch automatisch übersetzt werden.','String'=>'Zeichenkette','Exclude strings from automatic translation'=>'Zeichenketten von der automatischen Übersetzung ausschliessen','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Diese Zeichenketten nicht automatisch übersetzen (z. B. Namen, Fachbegriffe...)<br>Absätze, die diese Zeichenketten enthalten, werden weiterhin übersetzt, ausser dem angegebenen Teil.','Fix broken HTML'=>'Fehlerhaftes HTML korrigieren','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Allgemeiner Versuch, fehlerhaftes oder fehlendes HTML auf übersetzten Seiten zu korrigieren.<br/>','Force slash at end of home url:'=>'Schrägstrich am Ende der Home-URL erzwingen:','Ads a slash at the end of the home_url() function'=>'Fügt einen Schrägstrich am Ende der Funktion home_url() hinzu.','Show Both (recommended)'=>'Beide anzeigen (empfohlen)','Remove Country Locale'=>'Länder-Locale entfernen','Remove Region Independent Locale'=>'Regionsunabhängiges Locale entfernen','Remove duplicate hreflang'=>'Doppelte hreflang entfernen','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Wähle aus, welche hreflang-Tags auf deiner Website erscheinen.<br/>Wir empfehlen, beide Arten von hreflang-Tags anzuzeigen, wie in der <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google-Dokumentation</a> angegeben.<br/>Das Entfernen der Länder-Locale bei mehreren Länder-Locales derselben Sprache (z. B. Englisch UK und Englisch US) führt dazu, dass nur ein hreflang-Tag mit einem Link zu nur einer der Regions-Locales für diese Sprache angezeigt wird.','Default (example: en-US, fr-CA, etc.)'=>'Standard (Beispiel: en-US, fr-CA usw.)','Regional (example: en, fr, es, etc.)'=>'Regional (Beispiel: en, fr, es usw.)','HTML Lang Attribute Format'=>'Format des HTML-Lang-Attributs','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Änder das lang-Attribut des HTML-Tags in ein Format mit oder ohne Länderangabe. <br>In HTML sollte das lang-Attribut (<html lang="en-US">) verwendet werden, um die Sprache des Textinhalts anzugeben, damit der Browser den Inhalt korrekt anzeigen oder verarbeiten kann (z. B. für Silbentrennung, Styling, Rechtschreibprüfung usw.).','Load legacy Language Switcher'=>'Legacy Language Switcher laden','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Gilt für alle Arten von Sprachwechslern (Floating, Shortcode und Menü). Wenn aktiviert, greift die Website wieder auf den ursprünglichen Sprachwechsler zurück, der im Tab «Allgemeine Einstellungen» konfiguriert ist, und ersetzt die neue anpassbare Version. Deine bestehenden Wechsler-Einstellungen bleiben gespeichert, werden aber ignoriert, solange diese Option aktiv ist.','Load legacy SEO Pack Add-On'=>'Legacy SEO Pack Add-On laden','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Falls die kürzliche Migration zur neuen Slug-Umschreibung Probleme verursacht, setze dies auf Ja, um die alte Methode zu verwenden <br> Bitte <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">eröffne ein Support-Ticket</a> und teile uns die Probleme mit, die du hast.','Manual Translation Only'=>'Nur manuelle Übersetzung','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress scannt und speichert Zeichenketten proaktiv in der Datenbank, wenn Benutzer übersetzte Seiten aufrufen. <br>Diese Einstellung deaktiviert diese Funktion und erlaubt die Übersetzung und das Speichern von Zeichenketten nur innerhalb des Übersetzungs-Editors. <br>Deaktiviert auch die maschinelle Übersetzung ausserhalb des Übersetzungs-Editors und gibt Ihnen eine bessere Kontrolle über den Zeichenverbrauch, indem nur die Seiten übersetzt werden, die Sie im Übersetzungs-Editor besuchen.','Open language switcher only on click'=>'Sprachwechsler nur bei Klick öffnen','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Öffne den Shortcode-Sprachwechsler durch Anklicken statt durch Hover. <br>Schliesse ihn durch einen Klick darauf, durch Klicken an eine andere Stelle auf dem Bildschirm oder durch Drücken der Escape-Taste. Dies betrifft nur den Shortcode-Sprachwechsler.','Show opposite language in the language switcher'=>'Die jeweils andere Sprache im Sprachwechsler anzeigen','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Verwandelt den Sprachwechsler in einen Button, der die andere verfügbare Sprache anzeigt, nicht die aktuelle. <br>Funktioniert nur, wenn es genau zwei Sprachen gibt: die Standardsprache und eine Übersetzung. <br>Dies betrifft auch den Shortcode-Sprachwechsler und den schwebenden Sprachwechsler. <br>Um dies im Menü-Sprachwechsler zu erreichen, gehe zu Design->Menüs->Sprachwechsler und wähle «Andere Sprache».','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Hier klicken</a>, um das Datenbank-Optimierungstool aufzurufen.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Es hilft dabei, mögliche doppelte Übersetzungen zu entfernen, unnötige Daten zu bereinigen und mögliche Metadaten-Probleme zu beheben.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Hier</a> kannst du die letzten 5 SQL-Fehler einsehen, die TranslatePress betreffen, sofern vorhanden.','Troubleshooting'=>'Fehlerbehebung','Exclude Gettext strings'=>'Gettext-Zeichenketten ausschliessen','Debug'=>'Debug','Custom languages'=>'Benutzerdefinierte Sprachen','Miscellaneous options'=>'Sonstige Optionen','Exclude strings & pages'=>'Zeichenketten und Seiten ausschliessen','Automatic Translation Memory'=>'Automatischer Übersetzungsspeicher','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Gleiche Übersetzung für ähnliche Texte anwenden. Die Zeichenketten müssen eine Ähnlichkeit von 95 % aufweisen.<br>Hilft, bestehende Übersetzungen beim Korrigieren von Tippfehlern oder bei kleineren Anpassungen des Originaltextes nicht zu verlieren. <br>Wenn bereits eine Übersetzung für eine sehr ähnliche Originalzeichenkette existiert, wird diese automatisch für die aktuelle Originalzeichenkette verwendet.<br>Funktioniert nicht bei Änderungen an einem Text, der Teil eines Übersetzungsblocks ist, sofern der neue Text nicht manuell wieder in einen Übersetzungsblock eingefügt wird.<br>Jede Zeichenkette muss mindestens 50 Zeichen umfassen.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'WARNUNG: Diese Funktion kann die Seitenladezeiten in Sekundärsprachen negativ beeinflussen, insbesondere bei grossen Datenbanken (zum Beispiel Websites mit vielen Seiten oder Produkten). Falls Sie langsame Ladezeiten feststellen, deaktivieren Sie diese Funktion und versuchen Sie es erneut.','Fix missing dynamic content'=>'Fehlenden dynamischen Inhalt korrigieren','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Kann helfen, fehlenden mit JavaScript eingefügten Inhalt zu korrigieren. <br> Zeigt dynamisch eingefügten Inhalt kurzzeitig in der Originalsprache an, bevor die Übersetzungsanfrage abgeschlossen ist.','Filter Gettext wrapping from post content and title'=>'Gettext-Umschließung aus Beitragsinhalt und -titel filtern','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtert Gettext-Umschließungen wie #!trpst#trp-gettext aus allen aktualisierten Beitragsinhalten und -titeln. Betrifft nicht vorherige Beitragsinhalte. <br/><strong>Es wird empfohlen, vor dem Aktivieren eine Datenbanksicherung zu erstellen.</strong>','Filter Gettext wrapping from post meta'=>'Gettext-Umschließung aus Beitrags-Meta filtern','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtert Gettext-Umschließungen wie #!trpst#trp-gettext aus allen aktualisierten Beitrags-Meta. Betrifft nicht vorherige Beitrags-Meta. <br/><strong>Es wird empfohlen, vor dem Aktivieren eine Datenbanksicherung zu erstellen.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Google Translate API-Schlüssel','Add your API Key here...'=>'API-Schlüssel hier eingeben...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Besuchen Sie <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">diesen Link</a>, um zu erfahren, wie Sie einen API-Schlüssel einrichten, <strong>API-Kosten kontrollieren</strong> und HTTP-Referrer-Beschränkungen festlegen können.','Your HTTP referrer is: %s'=>'Ihr HTTP-Referrer lautet: %s','There was an error on the server processing your Google Translate key.'=>'Beim Verarbeiten Ihres Google Translate-Schlüssels ist ein Serverfehler aufgetreten.','There was an error with your Google Translate key.'=>'Mit Ihrem Google Translate-Schlüssel ist ein Fehler aufgetreten.','Please check your TranslatePress license key.'=>'Bitte überprüfen Sie Ihren TranslatePress-Lizenzschlüssel.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Für diese Website wurde keine aktive Lizenz erkannt.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Um die automatische Übersetzung mit TranslatePress AI zu aktivieren, benötigen Sie einen Lizenzschlüssel, den Sie durch Erstellung eines kostenlosen Kontos erhalten.','Create your Free Account'=>'Gratis Konto erstellen',' or '=>' oder ','Enter your license key'=>'Lizenzschlüssel eingeben',' Or %1$spurchase one here%2$s'=>' Oder %1$shier eine kaufen%2$s','Your free account includes: '=>'Dein Gratis-Konto beinhaltet: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Erhalte mehr AI-Wörter und schalte alle AI-Funktionen mit TranslatePress Pro frei.','You have a valid %s <strong>license</strong>.'=>'Du hast eine gültige %s <strong>Lizenz</strong>.',' words remaining. '=>' Wörter übrig. ','Recheck'=>'Erneut prüfen','Rechecking...'=>'Wird erneut geprüft...','Done.'=>'Fertig.','Manage your license & quota on the %s'=>'Verwalte deine Lizenz und dein Kontingent auf der %s','TranslatePress.com Account Page'=>'TranslatePress.com-Kontoseite','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'SEO-Unterstützung für Seiten-Slug, Seitentitel, Beschreibung sowie Social-Graph-Informationen für Facebook und Twitter. Das HTML-lang-Attribut wird korrekt gesetzt.','Enable Modules'=>'Module aktivieren','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Add-on-Module aktivieren, um TranslatePress zu erweitern und die Funktionalität deiner übersetzten Website zu verbessern.','More functionality with TranslatePress Pro.'=>'Mehr Funktionalität mit TranslatePress Pro.','Already a Pro User?'=>'Bereits Pro-Benutzer?','Activate License Key'=>'Lizenzschlüssel aktivieren','This add-on is not available on your current plan.'=>'Dieses Add-on ist in deinem aktuellen Plan nicht verfügbar.','Continue'=>'Weiter','The link you followed has expired. Please reload the page and try again.'=>'Der Link, dem du gefolgt bist, ist abgelaufen. Bitte lade die Seite neu und versuche es erneut.','A valid license is required to enable Automatic Translation.'=>'Eine gültige Lizenz ist erforderlich, um die automatische Übersetzung zu aktivieren.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Dein Lizenzschlüssel ist für diese URL deaktiviert. Aktiviere ihn neu über <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Websites verwalten.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Lizenzschlüssel stimmt nicht überein.</strong> Die eingegebene Lizenz passt nicht zur installierten TranslatePress-Version.</p><p>Bitte überprüfe, dass du die korrekte Version für deine Lizenz aus deinem TranslatePress Account installiert hast.</p>','Automatically translate your website using TranslatePress AI.'=>'Übersetze deine Website automatisch mit TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'Um die automatische Übersetzung mit TranslatePress AI zu aktivieren, verwende bitte deinen Lizenzschlüssel von','your account.'=>'deinem TranslatePress Account.','Skip and continue with manual translation »'=>'Überspringen und mit manueller Übersetzung fortfahren »','Get Your Free TranslatePress AI License'=>'Kostenlose TranslatePress AI-Lizenz erhalten','Generate License'=>'Lizenz generieren','Creating a free account includes: '=>'Die Erstellung eines kostenlosen Accounts umfasst: ','Are you a TranslatePress PRO user?'=>'Bist du ein TranslatePress Pro-Nutzer?','Install & Activate your pro plugin.'=>'Installiere & aktiviere dein Pro-Plugin.','Skip this step'=>'Diesen Schritt überspringen','The email address you added is incorrect.'=>'Die eingegebene E-Mail-Adresse ist falsch.','Setup Complete'=>'Einrichtung abgeschlossen','You\'re ready to start translating!'=>'Du bist bereit zu übersetzen!','You have successfully set up TranslatePress for your website.'=>'Du hast TranslatePress für deine Website erfolgreich eingerichtet.','Receive '=>'Erhalte ','Yes, send me multilingual growth tips.'=>'Ja, senden Sie mir mehrsprachige Wachstumstipps.','Start translating'=>'Übersetzen starten','Sign Up and Start translating'=>'Registrieren und Übersetzen starten','Please upload a TranslatePress Pro plugin file.'=>'Bitte laden Sie eine Plugindatei von TranslatePress Pro hoch.','Upload error: '=>'Fehler beim Hochladen: ','Install failed: '=>'Installation fehlgeschlagen: ','Plugin installed, but entry file not found. '=>'Plugin installiert, aber Einstiegsdatei nicht gefunden. ','Activation error: '=>'Aktivierungsfehler: ','Invalid plugin specified.'=>'Ungültiges Plugin angegeben.','Invalid action specified.'=>'Ungültige Aktion angegeben.','Plugin deactivation failed.'=>'Plugin-Deaktivierung fehlgeschlagen.','Plugin activation failed: '=>'Plugin-Aktivierung fehlgeschlagen: ','First, install and activate TranslatePress Pro'=>'Installieren und aktivieren Sie zuerst TranslatePress Pro','Please upload the TranslatePress PRO zip archive from your'=>'Bitte laden Sie das ZIP-Archiv von TranslatePress PRO aus Ihrem','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'Installieren und aktivieren','Installed Pro versions'=>'Installierte Pro-Versionen','« Go back'=>'« Zurück','Activate License »'=>'Lizenz aktivieren »','You are trying to add an invalid additional language. Please select a valid option.'=>'Sie versuchen, eine ungültige Zusatzsprache hinzuzufügen. Bitte wählen Sie eine gültige Option aus.','Please add an additional language.'=>'Bitte füge eine zusätzliche Sprache hinzu.','You are trying to add an invalid default language. Please select a valid option.'=>'Du versuchst, eine ungültige Standardsprache hinzuzufügen. Bitte wähle eine gültige Option.','You need to select a default language.'=>'Du musst eine Standardsprache auswählen.','Configure Site Languages'=>'Website-Sprachen konfigurieren','Select the default and additional languages for your website.'=>'Wähle die Standard- und zusätzlichen Sprachen für deine Website.','You can edit your site languages at any point.'=>'Du kannst deine Website-Sprachen jederzeit bearbeiten.','Additional Language'=>'Zusätzliche Sprache','Choose a secondary language...'=>'Wähle eine zweite Sprache...','Add Language'=>'Sprache hinzufügen','Choose a language...'=>'Wähle eine Sprache...','Add more than two languages with TranslatePress Pro.'=>'Füge mehr als zwei Sprachen mit TranslatePress Pro hinzu.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'Dein Lizenzschlüssel ist für diese URL deaktiviert. Aktiviere ihn neu unter <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Websites verwalten.','Add your License Key'=>'Füge deinen Lizenzschlüssel hinzu','Add your License Key to unlock all premium features. Find the License Key in your'=>'Füge deinen Lizenzschlüssel hinzu, um alle Premium-Funktionen freizuschalten. Den Lizenzschlüssel findest du in deinem','Your license is valid and active.'=>'Deine Lizenz ist gültig und aktiv.','« Go Back'=>'« Zurück','Set up Language Switcher'=>'Sprachwechsler einrichten','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'Wähle den Stil des Sprachwechslers. Weitere Anzeigeoptionen findest du in den Plugin-Einstellungen.','Displays a small language drop-down across your website, in a corner of your choosing.'=>'Zeigt ein kleines Sprach-Dropdown in einer Ecke deiner Wahl auf deiner Website an.','Switcher Location'=>'Position des Sprachwechslers','Apply a Template'=>'Vorlage anwenden','You can customize the design later'=>'Das Design kann später angepasst werden','Default Template'=>'Standardvorlage','Dark Template'=>'Dunkle Vorlage','Border Template'=>'Rahmenvorlage','Border'=>'Rahmen','Transparent Template'=>'Transparente Vorlage','Transparent'=>'Transparent','Welcome to TranslatePress'=>'Willkommen bei TranslatePress','Quick guided setup to configure TranslatePress in no time!'=>'Schnelle geführte Einrichtung, um TranslatePress im Handumdrehen zu konfigurieren!','It takes less than a minute.'=>'Es dauert weniger als eine Minute.','Scanning item %1$d of %2$d...'=>'Element %1$d von %2$d wird gescannt...','Manually translated'=>'Manuell übersetzt','Automatically translated'=>'Automatisch übersetzt','Not translated'=>'Nicht übersetzt','Bulk Actions'=>'Mehrfachaktionen','Delete entries'=>'Einträge löschen','Edit'=>'Bearbeiten','Delete'=>'Löschen','Filter'=>'Filter','Clear filters'=>'Filter zurücksetzen','Add New'=>'Neu hinzufügen','Rescan plugins and theme for strings'=>'Plugins und Theme erneut nach Zeichenketten scannen','Scanning plugins and theme for strings...'=>'Plugins und Theme werden nach Zeichenketten gescannt...','Plugins and theme scan is complete'=>'Scan der Plugins und des Themes abgeschlossen','Plugins and theme scan did not finish due to an error'=>'Der Scan der Plugins und des Themes wurde aufgrund eines Fehlers nicht abgeschlossen','Import / Export'=>'Import / Export','items'=>'Elemente','See More'=>'Mehr anzeigen','See Less'=>'Weniger anzeigen','Apply'=>'Anwenden','No strings match your query.'=>'Keine Zeichenketten entsprechen deiner Abfrage.','Try to rescan plugins and theme for strings.'=>'Versuche, Plugins und Theme erneut nach Zeichenketten zu scannen.','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'Beim Laden der Ergebnisse ist ein Fehler aufgetreten. Höchstwahrscheinlich wurdest du abgemeldet. Seite neu laden?','found in translation'=>'in Übersetzung gefunden','Select All'=>'Alle auswählen','Select Visible'=>'Sichtbare auswählen','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'Du bist dabei, diese Aktion für alle Zeichenketten auszuführen, die deinem Filter entsprechen, nicht nur für die sichtbar ausgewählten. Um die Aktion nur für die sichtbaren Zeichenketten auszuführen, klicke im Dropdown-Menü der Tabellenüberschrift auf "Sichtbare auswählen".','You are about to perform this action only on the visible strings. To perform the action on all the strings matching the filter click "Select All" from the table header dropdown.'=>'Du bist dabei, diese Aktion nur für die sichtbaren Zeichenketten auszuführen. Um die Aktion für alle Zeichenketten auszuführen, die dem Filter entsprechen, klicke im Dropdown-Menü der Tabellenüberschrift auf "Alle auswählen".','To continue please type the word:'=>'Gib zum Fortfahren das Wort ein:','The word typed was incorrect. Action was cancelled.'=>'Das eingegebene Wort war falsch. Die Aktion wurde abgebrochen.','Warning: This action cannot be undone. Deleting a string will remove its current translation. The original string will appear again in this interface after TranslatePress detects it. This action is NOT equivalent to excluding the string from being translated again.'=>'Warnung: Diese Aktion kann nicht rückgängig gemacht werden. Das Löschen einer Zeichenkette entfernt ihre aktuelle Übersetzung. Die Originalzeichenkette erscheint erneut in dieser Oberfläche, nachdem TranslatePress sie erkannt hat. Diese Aktion ist NICHT gleichbedeutend damit, die Zeichenkette von einer erneuten Übersetzung auszuschliessen.','%d original entries and their translations were deleted.'=>'%d Originaleinträge und deren Übersetzungen wurden gelöscht.','Navigate to next page'=>'Zur nächsten Seite navigieren','Navigate to previous page'=>'Zur vorherigen Seite navigieren','Navigate to first page'=>'Zur ersten Seite navigieren','Navigate to last page'=>'Zur letzten Seite navigieren','Type a page number to navigate to'=>'Eine Seitenzahl eingeben, zu der navigiert werden soll','Incorrect page number. Type a page number between 1 and total number of pages'=>'Falsche Seitenzahl. Eine Seitenzahl zwischen 1 und der Gesamtanzahl der Seiten eingeben.','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'Durchsuche Original- und übersetzte Zeichenketten, die die eingegebenen Schlüsselwörter enthalten und gleichzeitig den ausgewählten Filtern entsprechen. Setze eine Zeichenkette in Anführungszeichen für eine exakte Übereinstimmung: "Zeichenkette"','Filter strings according to selected translation status, filters and keywords and selected filters'=>'Zeichenketten gemäss ausgewähltem Übersetzungsstatus, Filtern und Schlüsselwörtern sowie ausgewählten Filtern filtern','Removes selected filters'=>'Entfernt ausgewählte Filter','See options for selecting all strings'=>'Optionen zum Auswählen aller Zeichenketten anzeigen','Click to sort strings by this column'=>'Klicken, um Zeichenketten nach dieser Spalte zu sortieren','Language in which the translation status filter applies. Leave unselected for the translation status to apply to ANY language'=>'Sprache, für die der Übersetzungsstatus-Filter gilt. Nicht auswählen, damit der Übersetzungsstatus für JEDE Sprache gilt.','Search'=>'Suchen','Slugs that are not found in either one of the other categories.'=>'Slugs, die in keiner der anderen Kategorien gefunden werden.','Plugins and Theme String Translation'=>'Zeichenkettenübersetzung für Plugins und Themes','Gettext'=>'Gettext','Search Gettext Strings'=>'Gettext-Zeichenketten durchsuchen','ID'=>'ID','Original String'=>'Original-String','Translation'=>'Übersetzung','Filter by domain'=>'Nach Domain filtern','Filter by type'=>'Nach Typ filtern','Email text'=>'E-Mail-Text','Emails String Translation'=>'E-Mail-String-Übersetzung','Emails'=>'E-Mails','Search Email Strings'=>'E-Mail-Strings suchen','User Inputted String Translation'=>'Benutzereingabe-String-Übersetzung','Regular'=>'Regulär','Search Regular Strings'=>'Reguläre Strings suchen','Filter by Translation Block'=>'Nach Übersetzungsblock filtern','URL Slugs Translation'=>'URL-Slug-Übersetzung','String Translation Editor'=>'String-Übersetzungs-Editor','TranslatePress has detected and cleaned up some failed translation entries in your database following %1$san isolated incident%2$s. No further action is required.'=>'TranslatePress hat im Anschluss an %1$seinen isolierten Vorfall%2$s einige fehlgeschlagene Übersetzungseinträge in deiner Datenbank erkannt und bereinigt. Es sind keine weiteren Massnahmen erforderlich.','Post Slug'=>'Beitrags-slug','Invalid language code'=>'Ungültiger Sprachcode','First by browser language, then IP address (recommended)'=>'Zuerst nach Browsersprache, dann nach IP-Adresse (empfohlen)','First by IP address, then by browser language'=>'Zuerst nach IP-Adresse, dann nach Browsersprache','Only by browser language'=>'Nur anhand der Browsersprache','Only by IP address'=>'Nur anhand der IP-Adresse','A popup appears asking the user if they want to be redirected'=>'Ein Popup fragt den Benutzer, ob er weitergeleitet werden möchte','Redirect directly (*not recommended)'=>'Direkt weiterleiten (*nicht empfohlen)','Pop-up window over the content'=>'Popup-Fenster über dem Inhalt','Hello bar before the content'=>'Hello-Leiste vor dem Inhalt','WARNING. Cannot determine your language preference based on your current IP.<br>This is most likely because the website is on a local environment.'=>'WARNUNG. Deine Sprachpräferenz kann nicht anhand deiner aktuellen IP-Adresse bestimmt werden.<br>Das liegt höchstwahrscheinlich daran, dass die Website in einer lokalen Umgebung läuft.','Go to <a href="%s" target="_self">Advanced</a> tab to change this feature\'s settings'=>'Wechsle zum Tab <a href="%s" target="_self">Erweitert</a>, um die Einstellungen dieser Funktion zu ändern.','User Language Detection Method'=>'Methode zur Spracherkennung des Benutzers','Select how the language should be detected for first time visitors.<br>The visitor\'s last displayed language will be remembered through cookies.'=>'Wähle aus, wie die Sprache für Erstbesucher erkannt werden soll.<br>Die zuletzt angezeigte Sprache des Besuchers wird über Cookies gespeichert.','User Notification Popup'=>'Benachrichtigungs-Popup für Benutzer','A popup appears asking the user if they want to be redirected.'=>'Ein Popup fragt den Benutzer, ob er weitergeleitet werden möchte.','Popup Type'=>'Popup-Typ','Popup Text'=>'Popup-Text','The same text is displayed in all languages. <br>A selecting language switcher will be appended to the pop-up. The detected language is pre-selected.'=>'Der gleiche Text wird in allen Sprachen angezeigt. <br>Ein Sprachumschalter wird dem Popup angehängt. Die erkannte Sprache ist vorausgewählt.','Button Text'=>'Button-Text','Write the text you wish to appear on the button..'=>'Gib den Text ein, der auf dem Button erscheinen soll..','Close Button Text'=>'Schliessen-Button-Text','Write the text you wish to appear on the close button. Leave empty for just the close button.'=>'Gib den Text ein, der auf dem Schliessen-Button erscheinen soll. Leer lassen, um nur den Schliessen-Button anzuzeigen.','Bad request. There was an error accessing the DeepL API.'=>'Ungültige Anfrage. Beim Zugriff auf die DeepL API ist ein Fehler aufgetreten.','The API key entered is invalid.'=>'Der eingegebene API-Schlüssel ist ungültig.','The API resource could not be found.'=>'Die API-Ressource konnte nicht gefunden werden.','The request size is too large.'=>'Die Anfragegrösse ist zu gross.','The request is too long.'=>'Die Anfrage ist zu lang.','Too many requests. Please try again later.'=>'Zu viele Anfragen. Bitte versuche es später noch einmal.','Your translation quota has been reached.'=>'Dein Übersetzungskontingent ist aufgebraucht.','We could not process your request. Please try again later.'=>'Wir konnten deine Anfrage nicht verarbeiten. Bitte versuche es später noch einmal.','There is an error on the DeepL service and your request could not 